VALUES
  ('social-worker-moex-00591', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關綜融取向社會工作以及其對個案工作的影響，下列敘述何者正確？①受到折衷學派社工理論', '["將社工員視為案主的一個引導者", "認為案主是以被壓迫來交換資源", "認為案主 自己必須先有意識覺醒", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00592', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於社會個案工作定義的敘述，下列何者錯誤？', '["個案工作兼具藝術與科學，有效的服務需立基於人類行為相關的知識與專業技巧之上", "個案工作是經由對個人及所處環境有意識的調整，達到促進成長的一連串過程", "個案工作介入的生態範圍為微視系統，為滿足個體本身的需求，並不涉及中介系統與鉅視系統", "個案工作透過面對面的關係來幫助個體和家庭解決內在心理、人際關係、社會經濟和環境的 問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00593', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於「以證據為基礎的實務」之敘述，下列何者錯誤？', '["以證據為基礎的實務乃是針對特定介入方式所做的一系列成效研究之結果，所形成的實證共識", "以證據為基礎的實務介入程序涉及專業社會工作者的應變智慧，因此無法標準化或手冊化", "以證據為基礎的實務步驟包括：形成問題、蒐集證據、評估證據、運用證據、評估執行程序", "以證據為基礎的實務需要專業社會工作者成為終身學習者（lifelong learner），才能因應不斷變 動的知識、理論與案主需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00594', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者對於個體的「生理面向」之理解，下列敘述何者錯誤？', '["進行生理面向評估時，需隔離其他社會文化因素，方能較為精準", "個體的生理發展隨著生命週期的不同階段，會與環境持續交互影響", "環境與生理的配適程度會影響個體的生命機會與生活型態", "先天基因與後天養育皆會影響個體的發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00595', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關危機干預模式的敘述，下列何者正確？', '["當個體身心狀態出現失衡時，就是出現危機", "干預的基本目標是協助減輕症狀而非解決問題", "生育、喬遷新居或是戀愛相關問題不屬危機干預範圍", "通常危機狀態在沒有外力介入下，需8～12週才會停止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00596', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關生態觀點的敘述，下列何者正確？', '["棲息地（habitues）指的是個人在所屬社會所占的地位和角色", "立基點（niche）是指有機體在特定文化脈絡中的成長環境", "人有能力經由依附連結關係，形成最佳人際關聯", "立基點（niche）提供社工員分析人與環境交互影響的架構"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00597', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在服務受暴婦女時，抱持「發掘及運用案主本身具備的能力來解決問題」及「對案主 抱持信任，從案主身上看到可能性」之信念來介入。請問這位社會工作者採用的是下列那一種觀 點或取向？', '["任務中心取向", "危機干預取向", "優勢觀點", "系統觀點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00598', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會個案工作中，評估案主的社會網絡（socialnetwork）是重要的一環。對於社會網絡的敘述， 下列何者錯誤？', '["社會網絡是個體連接關係的結構與數量", "社會網絡是多面向與複雜的社會關係", "社會網絡比較不支持案主的負向行為", "社會網絡所提供的支持能緩衝案主壓力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00599', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '家系圖是經常使用在評估階段的視覺化工具，繪製家系圖最能協助社會工作者下列那一個評估 面向？', '["了解案主和其他系統間的資源交換", "掌握案主世代關係的家庭互動模式", "檢視案主生活空間所處的環境", "探索宗教信仰對案主的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00600', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關家庭系統評估面向的敘述，下列何者正確？①要能夠呈現家庭環境脈絡  ②家庭是個人的次', '["要能分析家庭系統與次系統", "能說明家庭的關係與凝聚力", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
